external_knowledge:
- "more luxurious seas" refers to tickets with fares greater than 20.0;
- "average waters they've crossed" refers to the average fare paid by each passenger;
- "cost more than a small fortune" refers to an average fare greater than 50.0;

sql:
SELECT passenger_id, age, sex, name, survived, embarked
FROM passengers
WHERE age > 50 AND sex = 'female';

SELECT name
FROM passengers
WHERE fare > 2 * (SELECT AVG(fare) FROM passengers);

SELECT passenger_id, name, age, ticket
FROM passengers
WHERE age BETWEEN 20 AND 29;

SELECT name, age, sex
FROM passengers
WHERE is_alone = 1 AND age > 50;

SELECT name, cabin_class
FROM passengers
WHERE age > 30;

SELECT name, survived, ticket, fare, cabin, cabin_class
FROM passengers
WHERE survived = 1 AND cabin IS NOT NULL;

SELECT AVG(passengers.age) AS average_age
FROM passengers
WHERE passengers.survived = 1 AND passengers.family_size > 1;
